function acessarPainel(usuario) {
  if (!usuario) {
    console.log("Usuário ausente.");
    return;
  }

  if (!usuario.autenticado) {
    console.log("Usuário não autenticado.");
    return;
  }

  if (!usuario.temPermissao) {
    console.log("Usuário sem permissão.");
    return;
  }

  console.log("Acesso liberado ao painel.");
}

function processarPagamento(valor) {
  if (valor <= 0) {
    console.log("Valor inválido para pagamento.");
    return;
  }

  console.log("Pagamento em processamento.");
}
